<script setup lang="ts">/* MultiAngleVisualNode — 可视化多角度 */import { computed } from 'vue';import { Handle, Position } from '@vue-flow/core';import { useCanvasStore } from '@/stores/canvasStore'
const p=defineProps<{id:string;data:any;selected?:boolean}>();const cs=useCanvasStore();const d=computed(()=>p.data||{})
function patch(k:string,v:number){cs.updateNodeData(p.id,{[k]:v})}
function run(){const parts=[`方位:${d.value.azimuth||0}°`,`俯仰:${d.value.elevation||0}°`,`距离:${d.value.distance||5}`];cs.updateNodeData(p.id,{outputPrompt:parts.join('，'),status:'success',progress:100})}</script>
<template><div class="x" :class="{sel:selected}" :style="{borderColor:selected?'#ec4899':'var(--border)'}"><div class="xh"><div class="xi" style="background:rgba(236,72,153,.18);color:#f9a8d4"><JcIcon name="360" style="font-size:13px" /></div><div class="xl">多角度</div><button class="xr" @pointerdown.stop @click.stop="run"><JcIcon name="auto_awesome" /></button></div><div class="xb" @mousedown.stop><div class="rw"><label style="font-size:10px;width:36px">方位</label><input class="xi2" style="flex:1" type="number" :value="data.azimuth||0" @input="patch('azimuth',Number(($event.target as any).value))"/></div><div class="rw"><label style="font-size:10px;width:36px">俯仰</label><input class="xi2" style="flex:1" type="number" :value="data.elevation||0" @input="patch('elevation',Number(($event.target as any).value))"/></div><div class="rw"><label style="font-size:10px;width:36px">距离</label><input class="xi2" style="flex:1" type="number" :value="data.distance||5" @input="patch('distance',Number(($event.target as any).value))"/></div><div v-if="data.outputPrompt" class="xo">{{data.outputPrompt}}</div></div><Handle type="source" :position="Position.Right" :style="{background:'#ec4899',width:10,height:10,border:'none'}"/></div></template>
<style scoped>.x{width:280px;border:2px solid var(--border);border-radius:12px;background:var(--paper);box-shadow:var(--jc-shadow-sm);color:var(--ink1)}.x.sel{border-color:#ec4899}.xh{display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid var(--border2)}.xi{width:24px;height:24px;border-radius:6px;display:flex;align-items:center;justify-content:center}.xl{flex:1;font-size:13px;font-weight:600}.xr{width:26px;height:26px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink2);cursor:pointer;display:flex;align-items:center;justify-content:center}.xb{padding:10px;display:flex;flex-direction:column;gap:6px}.xi2{width:100%;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink1);padding:5px 8px;font-size:11px;outline:none;font:inherit}.rw{display:flex;gap:4px;align-items:center}.xo{max-height:100px;overflow:auto;white-space:pre-wrap;padding:6px;border-radius:4px;background:var(--surface);font-size:11px;word-break:break-all}</style>
